INSERT INTO maestro_vocabulary (vocab_type, name, definition, display_order) VALUES
('fm_type','Grant','Funding application with a hard external deadline. Requires Financial Gate review when co-financing applies.',1),
('fm_type','Application','Programme or accelerator to join. YC, residencies, fellowships. Freya alert on creation.',2),
