('fm_type','Roundtable','Multi-seat organism deliberation. Creates Library stub with Entry ID.',23),
('fm_type','Seat Chronicle','Session record for a specific seat. Creates Library stub automatically.',24),
('fm_type','News','External news or organism announcement. Alert fires on day of insertion.',25),
('fm_type','Visual Identity','Brand asset — logo, colour system, typography. Frankie Branding keeper.',26),
('fm_type','Other','Does not fit any of the above types. Flag for Il Maestro to review.',27);
